import { auth } from '@/api/auth'
import { storage } from '@/utils/storage'

// 认证服务
export const authService = {
  // 登录
  async login(credentials, remember) {
    const response = await auth.loginWithPassword(credentials)
    if (response.data?.code === 200) {
      const { access, refresh } = response.data.data
      storage.saveAuth({ access, refresh }, remember)
      if (remember) {
        storage.savePhone(credentials.phone)
      }
    }
    return response
  },

  // 登出
  async logout() {
    try {
      await auth.logout()
    } finally {
      storage.clearAuth()
    }
  },

  // 检查认证状态
  isAuthenticated() {
    const authData = storage.getAuth()
    if (!authData) return false
    return authData.expiration > new Date().getTime()
  }
}
